import functools
import time
import threading

class RateLimiter:
    def __init__(self, max_calls, period):
        self.max_calls = max_calls
        self.period = period
        self.calls = 0
        self.last_call = time.time()
        self.lock = threading.Lock()

    def allow(self):
        with self.lock:
            now = time.time()
            if now - self.last_call < self.period:
                if self.calls >= self.max_calls:
                    return False
                self.calls += 1
            else:
                self.calls = 1
                self.last_call = now
            return True

def rate_limited(max_calls, period):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            limiter = RateLimiter(max_calls, period)
            if not limiter.allow():
                raise Exception("Rate limit exceeded")
            return func(*args, **kwargs)
        return wrapper
    return decorator

# Example usage:
@rate_limited(5, 60)  # 5 calls per minute
def example_function():
    print("Example function called")

for _ in range(10):
    try:
        example_function()
    except Exception as e:
        print(e)
```

This code defines a `RateLimiter` class that tracks the number of calls within a given time period. The `rate_limited` decorator uses this class to enforce the rate limit on a function. If the rate limit is exceeded, it raises an exception. The example usage demonstrates how to apply the decorator to a function and handle the rate limit exception.

