import functools
import time
import random

def retry(max_attempts, delay=1, jitter=True):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            attempts = 0
            while attempts < max_attempts:
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    attempts += 1
                    if attempts < max_attempts:
                        delay_time = delay + (random.random() * delay * 2 if jitter else 0)
                        time.sleep(delay_time)
                        print(f"Attempt {attempts} failed with error: {str(e)}. Retrying in {delay_time} seconds.")
                    else:
                        raise
        return wrapper
    return decorator

# Example usage:
@retry(max_attempts=3, delay=2, jitter=True)
def example_function():
    # Simulate a function that sometimes fails
    if random.random() < 0.5:
        raise Exception("Example error")
