import ast
from flake8 import Plugin
from flake8 import options

class BlindExceptPlugin(Plugin):
    name = 'flake8-blind-except'
    version = '1.0'
    message = 'Blind except statement found'

    def match(self, tree):
        return any(isinstance(node, ast.Try) for node in ast.walk(tree))

    def run(self, tree, filename):
        for node in ast.walk(tree):
            if isinstance(node, ast.Try):
                for handler in node.handlers:
                    if isinstance(handler, ast.ExceptHandler):
                        if not handler.type:
                            self.add_error(self.message, node.lineno, node.col_offset)

def main():
    parser = options.get_parser()
    args = parser.parse_args()
    plugin = BlindExceptPlugin()
    plugin.run_tree(ast.parse(open(args.filename).read()))

if __name__ == '__main__':
    main()
```

To use this plugin, you'll need to install the `flake8` and `flake8-blind-except` packages. You can do this by running the following command in your terminal:

```bash
pip install flake8 flake8-blind-except
```

You can then use the plugin by running the following command in your terminal:

```bash
flake8 --plugin=flake8-blind-except your_file.py
```

This will check your file for blind except statements and report any it finds.
